## 4. CORREÇÕES DETALHADAS

### 🛡️ **CORREÇÃO 1: Implementar Middleware JWT Keycloak**

**Arquivo:** `src/middlewares/AuthMiddleware.ts` (CRIAR)

```typescript
import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { environments } from '../config/environments';
import { Log } from '../helpers/LogsHelper';

interface AuthenticatedRequest extends Request {
    user?: {
        sub: string;
        email: string;
        preferred_username: string;
        realm_access: {
            roles: string[];
        };
        resource_access: {
            [key: string]: {
                roles: string[];
            };
        };
        content: {
            tipoEntidadeEmpresa: string;
            cpfCnpjEmpresa: string;
            tipoPerfilUsuario: string;
        };
    };
}

export class AuthMiddleware {
    public static authenticate(req: AuthenticatedRequest, res: Response, next: NextFunction) {
        try {
            const authHeader = req.headers.authorization;

            if (!authHeader || !authHeader.startsWith('Bearer ')) {
                Log('warn', 'AuthMiddleware', 'authenticate', 'Token não fornecido', { 
                    ip: req.ip, 
                    userAgent: req.get('User-Agent'),
                    endpoint: req.path 
                });
                return res.status(401).json({ 
                    error: 'Token de acesso requerido',
                    code: 'MISSING_TOKEN' 
                });
            }

            const token = authHeader.substring(7);

            // Validação da chave pública
            const publicKey = environments.keycloak_public_key;
            if (!publicKey) {
                Log('error', 'AuthMiddleware', 'authenticate', 'Chave pública Keycloak não configurada');
                return res.status(500).json({ 
                    error: 'Configuração de autenticação inválida',
                    code: 'CONFIG_ERROR' 
                });
            }

            // Formatação da chave pública
            const formattedKey = `-----BEGIN PUBLIC KEY-----\n${publicKey}\n-----END PUBLIC KEY-----`;

            // Verificação do JWT
            const decoded = jwt.verify(token, formattedKey, {
                algorithms: ['RS256'], // Apenas RS256 permitido
                issuer: `${environments.keycloak_base_url}/realms/${environments.keycloak_realm}`,
                audience: environments.keycloak_client_id,
                clockTolerance: 30 // 30 segundos de tolerância para clock skew
            }) as any;

            // Validação de claims obrigatórios
            const requiredClaims = ['sub', 'exp', 'iat', 'iss', 'aud'];
            for (const claim of requiredClaims) {
                if (!decoded[claim]) {
                    Log('warn', 'AuthMiddleware', 'authenticate', `Claim obrigatório ausente: ${claim}`, { 
                        token: token.substring(0, 20) + '...' 
                    });
                    return res.status(401).json({ 
                        error: 'Token inválido',
                        code: 'INVALID_CLAIMS' 
                    });
                }
            }

            // Validação de expiração adicional
            const now = Math.floor(Date.now() / 1000);
            if (decoded.exp < now) {
                Log('warn', 'AuthMiddleware', 'authenticate', 'Token expirado', { 
                    exp: decoded.exp, 
                    now: now,
                    user: decoded.sub 
                });
                return res.status(401).json({ 
                    error: 'Token expirado',
                    code: 'TOKEN_EXPIRED' 
                });
            }

            // Anexar usuário à requisição
            req.user = decoded;

            Log('info', 'AuthMiddleware', 'authenticate', 'Autenticação bem-sucedida', { 
                user: decoded.sub,
                roles: decoded.realm_access?.roles || [],
                endpoint: req.path 
            });

            next();

        } catch (error) {
            Log('error', 'AuthMiddleware', 'authenticate', error, { 
                ip: req.ip, 
                userAgent: req.get('User-Agent'),
                endpoint: req.path 
            });

            if (error instanceof jwt.JsonWebTokenError) {
                return res.status(401).json({ 
                    error: 'Token inválido',
                    code: 'INVALID_TOKEN' 
                });
            }

            if (error instanceof jwt.TokenExpiredError) {
                return res.status(401).json({ 
                    error: 'Token expirado',
                    code: 'TOKEN_EXPIRED' 
                });
            }

            return res.status(500).json({ 
                error: 'Erro interno de autenticação',
                code: 'AUTH_ERROR' 
            });
        }
    }

    public static authorize(roles: string[] = []) {
        return (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
            try {
                if (!req.user) {
                    return res.status(401).json({ 
                        error: 'Usuário não autenticado',
                        code: 'NOT_AUTHENTICATED' 
                    });
                }

                // Verificação de roles se especificadas
                if (roles.length > 0) {
                    const userRoles = req.user.realm_access?.roles || [];
                    const hasRole = roles.some(role => userRoles.includes(role));

                    if (!hasRole) {
                        Log('warn', 'AuthMiddleware', 'authorize', 'Acesso negado - role insuficiente', { 
                            user: req.user.sub,
                            requiredRoles: roles,
                            userRoles: userRoles,
                            endpoint: req.path 
                        });

                        return res.status(403).json({ 
                            error: 'Permissão insuficiente',
                            code: 'INSUFFICIENT_PERMISSIONS' 
                        });
                    }
                }

                next();

            } catch (error) {
                Log('error', 'AuthMiddleware', 'authorize', error);
                return res.status(500).json({ 
                    error: 'Erro interno de autorização',
                    code: 'AUTHZ_ERROR' 
                });
            }
        };
    }
}
```

