### 🛡️ **CORREÇÃO 2: Middleware de Segurança Avançado**

**Arquivo:** `src/middlewares/SecurityMiddleware.ts` (CRIAR)

```typescript
import { Request, Response, NextFunction } from 'express';
import helmet from 'helmet';
import cors from 'cors';
import { environments } from '../config/environments';

export class SecurityMiddleware {
    public static configure() {
        const corsOptions = {
            origin: (origin: string | undefined, callback: Function) => {
                // Lista de origens permitidas
                const allowedOrigins = [
                    environments.url,
                    'https://app.gueptech.com.br',
                    'https://admin.gueptech.com.br'
                ];

                // Permite requisições sem origin (mobile apps, postman)
                if (!origin) return callback(null, true);

                if (allowedOrigins.includes(origin)) {
                    callback(null, true);
                } else {
                    callback(new Error('Origem não permitida pelo CORS'));
                }
            },
            credentials: true,
            optionsSuccessStatus: 200,
            methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
            allowedHeaders: [
                'Origin',
                'X-Requested-With',
                'Content-Type',
                'Accept',
                'Authorization',
                'X-API-Key'
            ]
        };

        const helmetOptions = {
            contentSecurityPolicy: {
                directives: {
                    defaultSrc: ["'self'"],
                    styleSrc: ["'self'", "'unsafe-inline'", "https://fonts.googleapis.com"],
                    scriptSrc: ["'self'"],
                    fontSrc: ["'self'", "https://fonts.gstatic.com"],
                    imgSrc: ["'self'", "data:", "https:"],
                    connectSrc: ["'self'"],
                    frameSrc: ["'none'"],
                    objectSrc: ["'none'"],
                    upgradeInsecureRequests: []
                }
            },
            hsts: {
                maxAge: 31536000, // 1 ano
                includeSubDomains: true,
                preload: true
            },
            frameguard: {
                action: 'deny'
            },
            noSniff: true,
            xssFilter: true,
            referrerPolicy: {
                policy: 'strict-origin-when-cross-origin'
            }
        };

        return [
            cors(corsOptions),
            helmet(helmetOptions),
            SecurityMiddleware.customSecurityHeaders
        ];
    }

    private static customSecurityHeaders(req: Request, res: Response, next: NextFunction) {
        // Headers de segurança customizados
        res.setHeader('Permissions-Policy', 
            'camera=(), microphone=(), geolocation=(), payment=()');

        res.setHeader('X-Content-Type-Options', 'nosniff');
        res.setHeader('X-Frame-Options', 'DENY');
        res.setHeader('X-XSS-Protection', '1; mode=block');

        // Remove headers que expõem tecnologia
        res.removeHeader('X-Powered-By');
        res.removeHeader('Server');

        next();
    }
}
```

