    keycloak_client_admin_id: sanitizeString(process.env.KEYCLOAK_CLIENT_ADMIN_ID),
    keycloak_client_admin_secret: sanitizeString(process.env.KEYCLOAK_CLIENT_ADMIN_SECRET),

    // URLs externas
