### 1. **Interface TypeScript para JWT Payload**
```typescript
// src/interfaces/KeycloakUser.ts
export interface KeycloakJWTPayload {
  iss: string;                    // Keycloak issuer
  sub: string;                    // Subject (user ID)
  aud: string | string[];         // Audience
  exp: number;                    // Expiration
  iat: number;                    // Issued at
  auth_time?: number;             // Authentication time
  jti: string;                    // JWT ID
  typ: string;                    // Token type
  azp: string;                    // Authorized party

  // Claims customizados
  preferred_username: string;
  email?: string;
  email_verified?: boolean;
  name?: string;
  family_name?: string;
  given_name?: string;

  // Claims específicos da aplicação
  realm_access?: {
    roles: string[];
  };
  resource_access?: {
    [client: string]: {
      roles: string[];
    };
  };

  // Claims customizados do negócio
  cpfCnpjEmpresa?: string;
  tipoEntidadeEmpresa?: 'MASTER' | 'INSTITUICAO' | 'PARCEIRO';
  tipoPerfilUsuario?: 'ADMIN' | 'USER' | 'VIEWER';
  instituicao_id?: string;
}

export interface AuthenticatedRequest extends Request {
  user: {
    payload: KeycloakJWTPayload;
    token: string;
    roles: string[];
    hasRole: (role: string) => boolean;
    hasAnyRole: (roles: string[]) => boolean;
  };
}
