### 2. **Middleware de Autenticação Robusto**
```typescript
// src/middlewares/KeycloakAuthMiddleware.ts
import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { environments } from '../config/environments';
import { KeycloakJWTPayload, AuthenticatedRequest } from '../interfaces/KeycloakUser';
import { Log } from '../helpers/LogsHelper';

export class KeycloakAuthError extends Error {
  constructor(
    message: string,
    public statusCode: number = 401,
    public code: string = 'AUTH_ERROR'
  ) {
    super(message);
    this.name = 'KeycloakAuthError';
  }
}

export class KeycloakAuthMiddleware {
  private static publicKey: string;

  static {
    this.initPublicKey();
  }

  private static initPublicKey() {
    if (!environments.keycloak_public_key) {
      throw new Error('KEYCLOAK_PUBLIC_KEY não configurada');
    }

    // Formatar chave pública se necessário
    this.publicKey = environments.keycloak_public_key
      .replace(/\\n/g, '\n')
      .replace(/^-----BEGIN.*KEY-----/, '-----BEGIN PUBLIC KEY-----')
      .replace(/-----END.*KEY-----$/, '-----END PUBLIC KEY-----');
  }

  /**
   * Extrai token JWT do header Authorization
   */
  private static extractToken(req: Request): string | null {
    const authHeader = req.headers.authorization;

    if (!authHeader) {
      return null;
    }

    const parts = authHeader.split(' ');

    if (parts.length !== 2 || parts[0] !== 'Bearer') {
      throw new KeycloakAuthError('Formato de Authorization header inválido');
    }

    return parts[1];
  }

  /**
   * Valida e decodifica o JWT
   */
  private static async validateToken(token: string): Promise<KeycloakJWTPayload> {
    try {
      const payload = jwt.verify(token, this.publicKey, {
        algorithms: ['RS256'],
        issuer: `${environments.keycloak_base_url}/realms/${environments.keycloak_realm}`,
        audience: environments.keycloak_client_id,
        clockTolerance: 30, // 30 segundos de tolerância para clock skew
      }) as KeycloakJWTPayload;

      return payload;
    } catch (error) {
      if (error instanceof jwt.TokenExpiredError) {
        throw new KeycloakAuthError('Token expirado', 401, 'TOKEN_EXPIRED');
      }
      if (error instanceof jwt.JsonWebTokenError) {
        throw new KeycloakAuthError('Token inválido', 401, 'INVALID_TOKEN');
      }

      Log('error', 'KeycloakAuthMiddleware', 'validateToken', error, { token: token.substring(0, 20) + '...' });
      throw new KeycloakAuthError('Erro na validação do token');
    }
  }

  /**
   * Extrai roles do payload JWT
   */
  private static extractRoles(payload: KeycloakJWTPayload): string[] {
    const roles: string[] = [];

    // Roles do realm
    if (payload.realm_access?.roles) {
      roles.push(...payload.realm_access.roles);
    }

    // Roles específicas do cliente
    if (payload.resource_access?.[environments.keycloak_client_id!]?.roles) {
      roles.push(...payload.resource_access[environments.keycloak_client_id!].roles);
    }

    return roles;
  }

  /**
   * Middleware principal de autenticação
   */
  public static authenticate() {
    return async (req: Request, res: Response, next: NextFunction) => {
      try {
        const token = this.extractToken(req);

        if (!token) {
          return res.status(401).json({ 
            error: 'Token de acesso requerido',
            code: 'MISSING_TOKEN'
          });
        }

        const payload = await this.validateToken(token);
        const roles = this.extractRoles(payload);

        // Anexa informações do usuário ao request
        const authReq = req as AuthenticatedRequest;
        authReq.user = {
          payload,
          token,
          roles,
          hasRole: (role: string) => roles.includes(role),
          hasAnyRole: (roleList: string[]) => roleList.some(role => roles.includes(role))
        };

        next();
      } catch (error) {
        if (error instanceof KeycloakAuthError) {
          return res.status(error.statusCode).json({
            error: error.message,
            code: error.code
          });
        }

        Log('error', 'KeycloakAuthMiddleware', 'authenticate', error, {
          url: req.url,
          method: req.method,
          headers: { authorization: req.headers.authorization?.substring(0, 20) + '...' }
        });

        return res.status(500).json({
          error: 'Erro interno de autenticação',
          code: 'INTERNAL_AUTH_ERROR'
        });
      }
    };
  }

  /**
   * Middleware de autorização por roles
   */
  public static authorize(requiredRoles: string | string[]) {
    const roles = Array.isArray(requiredRoles) ? requiredRoles : [requiredRoles];

    return (req: Request, res: Response, next: NextFunction) => {
      const authReq = req as AuthenticatedRequest;

      if (!authReq.user) {
        return res.status(401).json({
          error: 'Usuário não autenticado',
          code: 'NOT_AUTHENTICATED'
        });
      }

      if (!authReq.user.hasAnyRole(roles)) {
        return res.status(403).json({
          error: 'Permissões insuficientes',
          code: 'INSUFFICIENT_PERMISSIONS',
          required: roles,
          current: authReq.user.roles
        });
      }

      next();
    };
  }

  /**
   * Middleware de controle institucional
   */
  public static institutionControl() {
    return (req: Request, res: Response, next: NextFunction) => {
      const authReq = req as AuthenticatedRequest;
      const payload = authReq.user?.payload;

      if (!payload) {
        return res.status(401).json({
          error: 'Usuário não autenticado',
          code: 'NOT_AUTHENTICATED'
        });
      }

      // Usuários MASTER têm acesso total
      if (payload.tipoEntidadeEmpresa === 'MASTER') {
        return next();
      }

      // Aplica filtros institucionais automaticamente
      const body = req.body || {};
      const query = req.query || {};

      if (payload.cpfCnpjEmpresa) {
        body.cpf_cnpj_owner = payload.cpfCnpjEmpresa;
        query.cpf_cnpj_owner = payload.cpfCnpjEmpresa;
      }

      // Controle adicional para não-admins
      if (payload.tipoPerfilUsuario !== 'ADMIN') {
        body.cod_usuario_cadastro = payload.sub;
        query.cod_usuario_cadastro = payload.sub;
      }

      req.body = body;
      req.query = query;

      next();
    };
  }
}
