### 3. **Helper para Refresh Token**
```typescript
// src/helpers/KeycloakTokenHelper.ts
import axios from 'axios';
import { environments } from '../config/environments';

interface TokenResponse {
  access_token: string;
  refresh_token: string;
  expires_in: number;
  refresh_expires_in: number;
  token_type: string;
}

export class KeycloakTokenHelper {
  private static readonly TOKEN_URL = `${environments.keycloak_base_url}/realms/${environments.keycloak_realm}/protocol/openid-connect/token`;

  /**
   * Renova token usando refresh_token
   */
  public static async refreshToken(refreshToken: string): Promise<TokenResponse> {
    try {
      const response = await axios.post(this.TOKEN_URL, 
        new URLSearchParams({
          grant_type: 'refresh_token',
          client_id: environments.keycloak_client_id!,
          refresh_token: refreshToken,
        }), 
        {
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          timeout: 10000,
        }
      );

      return response.data;
    } catch (error: any) {
      if (error.response?.status === 400) {
        throw new Error('Refresh token inválido ou expirado');
      }

      throw new Error('Erro ao renovar token');
    }
  }

  /**
   * Introspect token para validação adicional
   */
  public static async introspectToken(token: string): Promise<any> {
    try {
      const response = await axios.post(
        `${environments.keycloak_base_url}/realms/${environments.keycloak_realm}/protocol/openid-connect/token/introspect`,
        new URLSearchParams({
          token,
          client_id: environments.keycloak_client_id!,
        }),
        {
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          timeout: 5000,
        }
      );

      return response.data;
    } catch (error) {
      throw new Error('Erro na introspecção do token');
    }
  }
}
