  KeycloakAuthMiddleware.institutionControl(),
  chamadoController.filtro
);

// Rotas com autorização específica
router.post('/create', 
  KeycloakAuthMiddleware.authorize(['chamado:create', 'admin']),
  KeycloakAuthMiddleware.institutionControl(),
  chamadoController.create
);

// Rotas administrativas
