### 5. **Middleware de Error Handling**
```typescript
// src/middlewares/ErrorHandlerMiddleware.ts
import { Request, Response, NextFunction } from 'express';
import { KeycloakAuthError } from './KeycloakAuthMiddleware';
import { Log } from '../helpers/LogsHelper';

export function errorHandler(
  error: Error,
  req: Request,
  res: Response,
  next: NextFunction
) {
  // Keycloak Auth Errors
  if (error instanceof KeycloakAuthError) {
    return res.status(error.statusCode).json({
      error: error.message,
      code: error.code,
      timestamp: new Date().toISOString(),
    });
  }

  // JWT Errors
  if (error.name === 'JsonWebTokenError') {
    return res.status(401).json({
      error: 'Token JWT inválido',
      code: 'INVALID_JWT',
      timestamp: new Date().toISOString(),
    });
  }

  if (error.name === 'TokenExpiredError') {
    return res.status(401).json({
      error: 'Token JWT expirado',
      code: 'JWT_EXPIRED',
      timestamp: new Date().toISOString(),
    });
  }

  // Log erro não tratado
  Log('error', 'ErrorHandlerMiddleware', 'unhandledError', error, {
    url: req.url,
    method: req.method,
    body: req.body,
  });

  // Erro genérico
  res.status(500).json({
    error: 'Erro interno do servidor',
    code: 'INTERNAL_SERVER_ERROR',
    timestamp: new Date().toISOString(),
  });
}
