```typescript
// src/controllers/ChamadoController.ts
import { Response, NextFunction } from "express";
import { AuthenticatedRequest } from "../interfaces/KeycloakUser";
import { Op } from "sequelize";
import { ChamadoModel } from "../models/ChamadoModel";

export default class ChamadoController {
  public async filtro(req: AuthenticatedRequest, res: Response, next: NextFunction) {
    try {
      const user = req.user.payload;
      const body = req.body;

      // Filtros já aplicados pelo middleware institutionControl()
      // body.cpf_cnpj_owner e body.cod_usuario_cadastro já estão definidos

      const conditions: any[] = [];

      if (body.protocolo) {
        conditions.push({ protocolo: body.protocolo });
      }

      if (body.cpf_cnpj_owner) {
        conditions.push({
          cpf_cnpj_owner: { [Op.like]: `%${body.cpf_cnpj_owner}%` }
        });
      }

      // ... resto da lógica

      const where = conditions.length > 0 ? { [Op.and]: conditions } : {};

      const page = body.current && body.current > 0 ? body.current - 1 : 0;
      const limit = body.limit ?? 20;
      const offset = page * limit;

      const resultado = await ChamadoModel.findAndCountAll({
        where,
        limit,
        offset,
        order: [["data_cadastro", "DESC"]],
      });

      return res.json({
        found: resultado.count,
        returned: resultado.rows.length,
        page: page + 1,
        limit,
        pages: Math.ceil(resultado.count / limit),
        rows: resultado.rows,
      });

    } catch (error) {
      next(error); // Passa para o error handler middleware
    }
  }
}
